5991 bool SCEVMinMaxExprContains(const SCEV *Root, const SCEV *OperandToFind,
5992                             SCEVTypes RootKind) {
5993   struct FindClosure {
5994     const SCEV *OperandToFind;
5995     const SCEVTypes RootKind; // Must be a sequential min/max expression.
5996     const SCEVTypes NonSequentialRootKind; // Non-seq variant of RootKind.
5997 
5998     bool Found = false;
5999 
6000     bool canRecurseInto(SCEVTypes Kind) const {
6001       // We can only recurse into the SCEV expression of the same effective type
6002       // as the type of our root SCEV expression, and into zero-extensions.
6003       return RootKind == Kind || NonSequentialRootKind == Kind ||
6004              scZeroExtend == Kind;
6005     };
6006 
6007     FindClosure(const SCEV *OperandToFind, SCEVTypes RootKind)
6008         : OperandToFind(OperandToFind), RootKind(RootKind),
6009           NonSequentialRootKind(
6010               SCEVSequentialMinMaxExpr::getEquivalentNonSequentialSCEVType(
6011                   RootKind)) {}
6012 
6013     bool follow(const SCEV *S) {
6014       Found = S == OperandToFind;
6015 
6016       return !isDone() && canRecurseInto(S->getSCEVType());
6017     }
6018 
6019     bool isDone() const { return Found; }
6020   };
6021 
6022   FindClosure FC(OperandToFind, RootKind);
6023   visitAll(Root, FC);
6024   return FC.Found;
6025 }
