6167 static std::optional<const SCEV *>
6168 createNodeForSelectViaUMinSeq(ScalarEvolution *SE, Value *Cond, Value *TrueVal,
6169                               Value *FalseVal) {
6170   if (!isa<ConstantInt>(TrueVal) && !isa<ConstantInt>(FalseVal))
6171     return std::nullopt;
6172 
6173   const auto *SECond = SE->getSCEV(Cond);
6174   const auto *SETrue = SE->getSCEV(TrueVal);
6175   const auto *SEFalse = SE->getSCEV(FalseVal);
6176   return createNodeForSelectViaUMinSeq(SE, SECond, SETrue, SEFalse);
